+    fn execute_pipeline_dry_run_requires_live_host() {
+        let root = std::env::temp_dir().join(format!(
+            "fwc-pipeline-dry-run-no-host-{}-{}",
+            std::process::id(),
+            uuid::Uuid::new_v4()
+        ));
