+        let path = root.join("notify.toml");
+        std::fs::write(
+            &path,
+            r#"
+[pipeline]
+name = "notify-on-new-issues"
+
+[[steps]]
+id = "fetch"
+operation = "github.search_issues"
+"#,
+        )
+        .unwrap();
+
+        let path_str = path.display().to_string();
